import React, { useState, useEffect } from 'react';
import API from '../api/axios';

const DepartmentMaster = () => {
    const [departments, setDepartments] = useState([]);
    const [formData, setFormData] = useState({ department: '', departmentShortName: '' });
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        fetchDepartments();
    }, []);

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            setDepartments(data);
        } catch (err) {
            alert('Error fetching departments');
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await API.post('/master/department', formData);
            setFormData({ department: '', departmentShortName: '' });
            fetchDepartments();
            alert('Department added successfully!');
        } catch (err) {
            alert('Error adding department');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ padding: '40px', color: 'white', background: '#0f172a', minHeight: '100vh' }}>
            <h2 style={{ fontSize: '2rem', marginBottom: '30px' }}>Department Master</h2>
            
            <form onSubmit={handleSubmit} style={{ maxWidth: '500px', marginBottom: '40px' }}>
                <div style={{ marginBottom: '15px' }}>
                    <label>Department Name</label>
                    <input 
                        type="text" 
                        required
                        value={formData.department}
                        onChange={e => setFormData({...formData, department: e.target.value})}
                        style={inputStyle}
                    />
                </div>
                
                <div style={{ marginBottom: '15px' }}>
                    <label>Department Short Name</label>
                    <input 
                        type="text" 
                        required
                        value={formData.departmentShortName}
                        onChange={e => setFormData({...formData, departmentShortName: e.target.value})}
                        style={inputStyle}
                    />
                </div>

                <button type="submit" disabled={loading} style={btnStyle}>
                    {loading ? 'Adding...' : 'Add Department'}
                </button>
            </form>

            <h3>Departments List</h3>
            <table style={tableStyle}>
                <thead>
                    <tr>
                        <th>Department Name</th>
                        <th>Short Name</th>
                    </tr>
                </thead>
                <tbody>
                    {departments.map(dept => (
                        <tr key={dept._id}>
                            <td>{dept.department}</td>
                            <td>{dept.departmentShortName}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

const inputStyle = { 
    width: '100%', 
    padding: '10px', 
    marginTop: '5px',
    borderRadius: '5px', 
    border: '1px solid #334155', 
    background: '#1e293b', 
    color: 'white',
    boxSizing: 'border-box'
};

const btnStyle = { 
    padding: '12px 20px', 
    background: 'linear-gradient(to right, #38bdf8, #818cf8)', 
    border: 'none', 
    borderRadius: '5px', 
    color: 'white', 
    fontWeight: 'bold', 
    cursor: 'pointer',
    width: '100%'
};

const tableStyle = {
    width: '100%',
    borderCollapse: 'collapse',
    marginTop: '20px',
    border: '1px solid #334155'
};

export default DepartmentMaster;
